var input = inputs.Length > 0 && inputs[0] != null ? inputs[0]! :
        new PixelBuffer(context.TileSize, context.TileSize);
    var offsetX = GetFloat(parameters, "offsetX", 0.1f);
    var offsetY = GetFloat(parameters, "offsetY", 0.1f);
    var blurRadius = GetInt(parameters, "blurRadius", 2);
    var shadowColor = GetColor(parameters, "shadowColor", Color.FromRgb(0, 0, 0));
    var opacity = GetFloat(parameters, "opacity", 0.5f);
    var spread = GetFloat(parameters, "spread", 0f);
    var mode = GetChoice(parameters, "mode", "dropShadow");

    var size = context.TileSize;
    var buffer = input.Clone();

    var sR = shadowColor.R / 255f * opacity;
    var sG = shadowColor.G / 255f * opacity;
    var sB = shadowColor.B / 255f * opacity;

    var offsetPixelsX = (int)(offsetX * size);
    var offsetPixelsY = (int)(offsetY * size);

    // Extract alpha channel
    var alpha = new float[size * size];
    for (var y = 0; y < size; y++)
    {
        for (var x = 0; x < size; x++)
        {
            var (_, _, _, aVal) = input.GetPixel(x, y);
            alpha[y * size + x] = aVal;

            // Apply spread: increase opaque region
            if (spread > 0f && aVal > 0.1f)
            {
                alpha[y * size + x] = Math.Clamp(aVal + spread * 0.3f, 0f, 1f);
            }
        }
    }

    // Apply Gaussian blur to alpha
    var blurred = blurRadius > 0 ? GaussianBlur(alpha, size, blurRadius) : alpha;

    if (mode == "dropShadow")
    {
        // Composite shadow behind original
        buffer.ParallelForEachPixel((x, y) =>
        {
            var sx = (x - offsetPixelsX + size) % size;
            var sy = (y - offsetPixelsY + size) % size;
            var shadowAlpha = blurred[sy * size + sx] * opacity;

            var (r, g, b, a) = buffer.GetPixel(x, y);

            if (shadowAlpha > 0f)
            {
                // Composite shadow behind: shadow * (1 - origAlpha) + orig
                var composited = shadowAlpha * (1f - a);
                buffer.SetPixel(x, y,
                    r + sR * composited,
                    g + sG * composited,
                    b + sB * composited,
                    Math.Clamp(a + composited, 0f, 1f));
            }
        });
    }
    else if (mode == "glow")
    {
        // Glow: shadow only where alpha is low, colored with shadow color
        buffer.ParallelForEachPixel((x, y) =>
        {
            var glowAlpha = blurred[y * size + x] * opacity;
            var (glowR, glowG, glowB, glowA) = buffer.GetPixel(x, y);

            // Glow shows through transparent areas
            if (glowAlpha > glowA)
            {
                var t = (glowAlpha - glowA) / glowAlpha;
                buffer.SetPixel(x, y,
                    Lerp(glowR, sR, t * 0.7f),
                    Lerp(glowG, sG, t * 0.7f),
                    Lerp(glowB, sB, t * 0.7f),
                    glowAlpha);
            }
        });
    }
    else // innerShadow
    {
        // Inner shadow: inset shadow on the interior of opaque regions
        buffer.ParallelForEachPixel((x, y) =>
        {
            var sx = (x + offsetPixelsX + size) % size;
            var sy = (y + offsetPixelsY + size) % size;
            var innerShadow = (1f - blurred[sy * size + sx]) * opacity;

            // Only apply to opaque interior
            var (innerR, innerG, innerB, innerA) = buffer.GetPixel(x, y);
            if (innerA > 0f && innerShadow > 0f)
            {
                var darken = 1f - innerShadow * 0.6f;
                buffer.SetPixel(x, y, innerR * darken, innerG * darken, innerB * darken, innerA);
            }
        });
    }

    return buffer;

private static float[] GaussianBlur(float[] input, int size, int radius)
{
    if (radius <= 0) return input;

    // Compute 1D Gaussian kernel
    var kernelSize = radius * 2 + 1;
    var kernel = new float[kernelSize];
    var sigma = radius / 2f;
    var sum = 0f;

    for (var i = 0; i < kernelSize; i++)
    {
        var x = i - radius;
        kernel[i] = MathF.Exp(-(x * x) / (2f * sigma * sigma));
        sum += kernel[i];
    }
    for (var i = 0; i < kernelSize; i++) kernel[i] /= sum;

    // Horizontal blur
    var temp = new float[size * size];
    for (var y = 0; y < size; y++)
    {
        for (var x = 0; x < size; x++)
        {
            var val = 0f;
            for (var k = 0; k < kernelSize; k++)
            {
                var sx = (x + k - radius + size) % size;
                val += input[y * size + sx] * kernel[k];
            }
            temp[y * size + x] = val;
        }
    }

    // Vertical blur
    var result = new float[size * size];
    for (var y = 0; y < size; y++)
    {
        for (var x = 0; x < size; x++)
        {
            var val = 0f;
            for (var k = 0; k < kernelSize; k++)
            {
                var sy = (y + k - radius + size) % size;
                val += temp[sy * size + x] * kernel[k];
            }
            result[y * size + x] = val;
        }
    }

    return result;
    }
}
